import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <nav className="bg-indigo-700 text-white p-4 shadow-lg flex justify-between items-center">
      {/* 標題指向首頁 (Home) */}
      <Link to="/" className="text-2xl font-bold tracking-tight flex items-center">
         <span className="mr-2">🌍</span> Sam's TPMS
      </Link>

      <div className="flex items-center">
        {user ? (
          <>
            {/* 1. 首頁連結：顯示全部旅遊清單 */}
            <Link to="/" className="mr-6 font-medium hover:text-indigo-200 transition">
              Home
            </Link>

            {/* 2. 重點：這就是你想要的 CRUD 管理按鈕 */}
            <Link 
              to="/manage-tours" 
              className="mr-6 bg-yellow-500 hover:bg-yellow-600 text-indigo-900 px-4 py-2 rounded-full font-bold text-sm shadow-md transition transform hover:scale-105"
            >
              ⚙️ Manage Tours
            </Link>

            <Link to="/profile" className="mr-6 hover:text-indigo-200 transition">
              Profile
            </Link>

            <div className="flex items-center border-l border-indigo-500 pl-6">
              <span className="mr-4 text-sm font-light text-indigo-100">
                Welcome, <span className="font-semibold">{user.username || 'Admin'}</span>
              </span>
              <button
                onClick={handleLogout}
                className="bg-red-500 px-4 py-1.5 rounded-md text-sm font-medium hover:bg-red-600 transition shadow-sm"
              >
                Logout
              </button>
            </div>
          </>
        ) : (
          <>
            <Link to="/login" className="mr-4 hover:text-indigo-200">Login</Link>
            <Link
              to="/register"
              className="bg-green-500 px-4 py-2 rounded-md font-medium hover:bg-green-600 transition shadow-sm"
            >
              Register
            </Link>
          </>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
